findings.suggestion:
BEFORE:
export class ScreenshotCapture {
  private provider: ScreenshotProvider
  constructor(provider: ScreenshotProvider) {
    this.provider = provider
  }
  async capture(): Promise<ScreenshotResult> {
    const buffer = await this.provider.capture()
    return { buffer, timestamp: Date.now() }
  }
}

AFTER:
export function captureScreenshot(
  provider: ScreenshotProvider,
): Promise<ScreenshotResult> {
  return provider.capture().then(buffer => ({
    buffer,
    timestamp: Date.now(),
  }))
}

WHY: Reduces indirection for a single-method, stateless wrapper. However, keep the class if lifecycle hooks or caching are planned.
